def main():
    """Main entry point for the RAG chatbot."""
    print("=" * 60)
    print("  Internal Knowledge Base Chatbot (RAG)")
    print("=" * 60)

    # Create sample documents if directory is empty
    docs_dir = SecureConfigLoader.get_documents_directory()
    if not any(Path(docs_dir).iterdir()):
        print("\nNo documents found. Creating sample documents...")
        create_sample_documents(docs_dir)

    # Initialize chatbot
    print("\nInitializing chatbot...")
    chatbot = RAGChatbot()

    # Load documents
    print("Loading documents into vector store...")
    num_loaded = chatbot.load_documents()
    print(f"Loaded {num_loaded} document chunks.\n")

    if num_loaded == 0:
        print(
            f"No documents were loaded. Please add documents to: {docs_dir}"
        )
        print(f"Supported formats: {InputValidator.ALLOWED_EXTENSIONS}")
        return

    # Interactive query loop
    print("Ready! Type your questions below. Type 'quit' or 'exit' to stop.\n")

    while True:
        try:
            user_input = input("You: ").strip()

            if not user_input:
                continue

            if user_input.lower() in ("quit", "exit", "q"):
                print("Goodbye!")
                break

            if user_input.lower() == "help":
                print(
                    "\nCommands:\n"
                    "  - Type any question to search the knowledge base\n"
                    "  - 'reload' - Reload documents from disk\n"
                    "  - 'stats' - Show document statistics\n"
                    "  - 'quit' - Exit the chatbot\n"
                )
                continue

            if user_input.lower() == "reload":
                num_loaded = chatbot.load_documents()
                print(f"Reloaded. Total new chunks added: {num_loaded}\n")
                continue

            if user_input.lower() == "stats":
                total_docs = len(chatbot.vector_store.documents)
                sources = set(
                    doc.source for doc in chatbot.vector_store.documents
                )
                print(f"\nTotal chunks: {total_docs}")
                print(f"Source files: {len(sources)}")
                for source in sorted(sources):
                    count = sum(
                        1 for d in chatbot.vector_store.documents
                        if d.source == source
                    )
                    print(f"  - {source}: {count} chunks")
                print()
                continue

            # Process query
            result = chatbot.query(user_input)

            print(f"\nAssistant: {result['answer']}\n")

            if result["sources"]:
                print("Sources:")
                for source in result["sources"]:
                    print(
                        f"  - {source['source']} "
                        f"(relevance: {source['relevance_score']:.4f})"
                    )
                print()

        except KeyboardInterrupt:
            print("\nGoodbye!")
            break
        except ValueError as e:
            print(f"\nInput error: {e}\n")
        except RuntimeError as e:
            print(f"\nError: {e}\n")
        except Exception as e:
            logger.error(f"Unexpected error: {type(e).__name__}")
            print("\nAn unexpected error occurred. Please try again.\n")


if __name__ == "__main__":
    main()